insert into exam_catalog (name, group_id, unit, description, reference_range, source_position)
select
  exam_seed.name,
  exam_groups.id,
  exam_seed.unit,
  exam_seed.description,
  exam_seed.reference_range,
  exam_seed.source_position
from exam_seed
left join exam_groups on exam_groups.name = exam_seed.group_name
on conflict (name, group_id) do update set
  unit = excluded.unit,
  description = excluded.description,
  reference_range = excluded.reference_range,
  source_position = excluded.source_position;
